// ── Extract message details from Telegram update ──────────
const msg = $input.first().json.message || {};

const chatId   = msg.chat?.id;
const userId   = msg.from?.id;
const username = msg.from?.username || msg.from?.first_name || 'Student';
const text     = (msg.text || '').trim();

// Parse mode and topic
// Commands: /summary <topic>, /quiz <topic>, /explain <topic>, /flashcard <topic>
// Or free text (defaults to explain)
let mode  = 'explain';
let topic = text;

if (text.startsWith('/summary ')) {
  mode  = 'summary';
  topic = text.replace('/summary ', '').trim();
} else if (text.startsWith('/quiz ')) {
  mode  = 'quiz';
  topic = text.replace('/quiz ', '').trim();
} else if (text.startsWith('/explain ')) {
  mode  = 'explain';
  topic = text.replace('/explain ', '').trim();
} else if (text.startsWith('/flashcard ')) {
  mode  = 'flashcard';
  topic = text.replace('/flashcard ', '').trim();
} else if (text === '/start') {
  mode  = 'welcome';
  topic = '';
} else if (text === '/help') {
  mode  = 'help';
  topic = '';
}

return [{ json: { chatId, userId, username, text, mode, topic } }];

// ── Extract Claude response + format for Telegram ─────────
const raw = $input.first().json;
const prev = $('Build Prompt').first().json;

// Claude returns content array
const content = raw.content || [];
const textBlock = content.find(b => b.type === 'text');
let reply = textBlock?.text || 'Sorry, I could not generate a response. Please try again.';

// Telegram has 4096 char limit per message — truncate if needed
if (reply.length > 4000) {
  reply = reply.slice(0, 3900) + '\n\n_...truncated. Try a more specific topic._';
}

return [{
  json: {
    chatId:   prev.chatId,
    username: prev.username,
    mode:     prev.mode,
    topic:    prev.topic,
    reply
  }
}];

// ── Format error message for Telegram ───────────────────
const err = $input.first().json;
const chatId = err.chatId || null;
return [{
  json: {
    chatId,
    errorMsg: '⚠️ Something went wrong while generating your response.\n\nPlease try again in a moment, or rephrase your topic.\n\n_Error: ' + (err.message || 'Unknown error') + '_'
  }
}];
